	private void GenerateSources(ReagentPrototype reagent)
	{
		List<ReagentSourceData> reagentSources = _chemistryGuideData.GetReagentSources(reagent.ID);
		if (reagentSources.Count == 0)
		{
			((Control)SourcesContainer).Visible = false;
			return;
		}
		((Control)SourcesContainer).Visible = true;
		foreach (ReagentSourceData item in from o in reagentSources
			orderby o.OutputCount, o.IdentifierString
			select o)
		{
			if (item is ReagentEntitySourceData reagentEntitySourceData)
			{
				((Control)SourcesDescriptionContainer).AddChild((Control)(object)new GuideReagentReaction(reagentEntitySourceData.SourceEntProto, reagentEntitySourceData.Solution, reagentEntitySourceData.MixingType, _prototype, _systemManager));
			}
			else if (item is ReagentReactionSourceData reagentReactionSourceData)
			{
				((Control)SourcesDescriptionContainer).AddChild((Control)(object)new GuideReagentReaction(reagentReactionSourceData.ReactionPrototype, _prototype, _systemManager));
			}
			else if (item is ReagentGasSourceData reagentGasSourceData)
			{
				((Control)SourcesDescriptionContainer).AddChild((Control)(object)new GuideReagentReaction(reagentGasSourceData.GasPrototype, reagentGasSourceData.MixingType, _prototype, _systemManager));
			}
		}
